import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { getMyTasks, updateTaskStatus } from '../services/api';
import { format } from 'date-fns';

const PriorityBadge = ({ p }) => {
  const s = { High: 'bg-red-100 text-red-700', Medium: 'bg-yellow-100 text-yellow-700', Low: 'bg-green-100 text-green-700' };
  return <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${s[p]}`}>{p}</span>;
};

export default function EmployeeTasks() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filterStatus, setFilterStatus] = useState('');
  const [selected, setSelected] = useState(null);
  const [updateForm, setUpdateForm] = useState({ status: '', progress: 0, notes: '' });

  const fetchTasks = () => {
    setLoading(true);
    getMyTasks({ status: filterStatus }).then(({ data }) => { setTasks(data); setLoading(false); }).catch(() => setLoading(false));
  };

  useEffect(() => { fetchTasks(); }, [filterStatus]);

  const openUpdate = (task) => {
    setSelected(task);
    setUpdateForm({ status: task.status, progress: task.progress || 0, notes: task.notes || '' });
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await updateTaskStatus(selected._id, updateForm);
      toast.success('Task updated!');
      setSelected(null);
      fetchTasks();
    } catch { toast.error('Update failed'); }
  };

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-display font-bold text-gray-900 dark:text-white">My Tasks</h2>
        <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)}
          className="px-4 py-2.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-sm text-gray-700 dark:text-gray-300 focus:outline-none">
          <option value="">All Status</option>
          <option>Pending</option><option>In Progress</option><option>Completed</option>
        </select>
      </div>

      {loading ? <div className="text-center py-12 text-gray-400">Loading tasks...</div> : tasks.length === 0 ? (
        <div className="text-center py-12 text-gray-400">No tasks assigned yet.</div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3">
          {tasks.map(task => (
            <div key={task._id} className="bg-white dark:bg-gray-800 rounded-2xl p-5 border border-gray-100 dark:border-gray-700 shadow-sm hover:shadow-md transition space-y-3">
              <div className="flex items-start justify-between gap-2">
                <h3 className="font-semibold text-gray-900 dark:text-white text-sm leading-snug">{task.title}</h3>
                <PriorityBadge p={task.priority} />
              </div>
              {task.description && <p className="text-xs text-gray-500 dark:text-gray-400 line-clamp-2">{task.description}</p>}
              <div className="space-y-1.5">
                <div className="flex justify-between text-xs text-gray-500">
                  <span>Progress</span><span>{task.progress || 0}%</span>
                </div>
                <div className="h-2 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${task.progress || 0}%` }} />
                </div>
              </div>
              <div className="flex items-center justify-between">
                <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${task.status === 'Completed' ? 'bg-green-100 text-green-700' : task.status === 'In Progress' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-600'}`}>{task.status}</span>
                {task.deadline && <span className="text-xs text-gray-400">📅 {format(new Date(task.deadline), 'MMM d')}</span>}
              </div>
              {task.notes && <p className="text-xs text-gray-400 italic bg-gray-50 dark:bg-gray-750 rounded-lg px-3 py-2">"{task.notes}"</p>}
              <button onClick={() => openUpdate(task)}
                className="w-full py-2 bg-indigo-50 hover:bg-indigo-100 dark:bg-indigo-900/30 dark:hover:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 text-sm font-medium rounded-xl transition">
                Update Status
              </button>
            </div>
          ))}
        </div>
      )}

      {selected && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-7 w-full max-w-md shadow-2xl">
            <h3 className="font-display font-bold text-xl text-gray-900 dark:text-white mb-1">Update Task</h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-5">{selected.title}</p>
            <form onSubmit={handleUpdate} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Status</label>
                <select value={updateForm.status} onChange={e => setUpdateForm({ ...updateForm, status: e.target.value })}
                  className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400">
                  <option>Pending</option><option>In Progress</option><option>Completed</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Progress: {updateForm.progress}%</label>
                <input type="range" min="0" max="100" value={updateForm.progress}
                  onChange={e => setUpdateForm({ ...updateForm, progress: Number(e.target.value) })}
                  className="w-full accent-indigo-600" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Notes</label>
                <textarea value={updateForm.notes} onChange={e => setUpdateForm({ ...updateForm, notes: e.target.value })}
                  rows={3} placeholder="Add a note..." className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:border-indigo-400 resize-none" />
              </div>
              <div className="flex gap-3 pt-1">
                <button type="button" onClick={() => setSelected(null)} className="flex-1 py-2.5 border border-gray-200 dark:border-gray-600 text-gray-600 dark:text-gray-400 rounded-xl text-sm font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl text-sm font-semibold transition">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
